import React from 'react';
import { Card, Stack, Divider, Text, Heading, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Clear',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={16}>
        <Stack gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface)">{city}</Heading>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{condition}</Text>
        </Stack>

        <Stack direction="horizontal" justify="between" align="center">
          <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
            {temperature}°{unit}
          </Text>
          <Stack gap={4} align="end">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Humidity: {humidity}%</Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Wind: {windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={8} />

        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Box
              key={index}
              paddingX={8}
              paddingY={8}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            >
              <Stack align="center" gap={4}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">{item.day ?? '-'}</Text>
                <Text size="xl">{item.icon ?? '☁️'}</Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
                  {item.high}°/{item.low}°
                </Text>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Divider,
  Container,
  Spacer,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{
    day?: string;
    icon?: string;
    high?: number;
    low?: number;
  }>;
}

export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "☁️", high: 25, low: 19 },
    { day: "Thu", icon: "🌧️", high: 22, low: 18 },
    { day: "Fri", icon: "☀️", high: 26, low: 21 }
  ]
}: Props) {
  const [cardHover, setCardHover] = useState(false);
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);

  return (
    <Container maxWidth="sm" padding={16}>
      <MotionKeyframes />
      <div
        onMouseEnter={() => setCardHover(true)}
        onMouseLeave={() => setCardHover(false)}
        style={{
          transition: 'transform 200ms ease-in-out',
          transform: cardHover ? 'translateY(-4px)' : 'none',
          animation: 'ggui-fadeIn 500ms ease-out'
        }}
        role="region"
        aria-label={`Weather information for ${city}`}
      >
        <Card
          shadow={cardHover ? "lg" : "md"}
          radius="xl"
          padding={24}
          border={true}
        >
          <Stack gap={20} direction="vertical" align="stretch">
            {/* Header: City Name */}
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                {city ?? "Unknown City"}
              </Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Today
              </Text>
            </Stack>

            {/* Main Conditions Section */}
            <Stack direction="horizontal" justify="between" align="center">
              <Stack gap={0}>
                <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
                  {temperature ?? 0}°{unit ?? "C"}
                </Heading>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {condition ?? "Clear"}
                </Text>
              </Stack>
              <Text size="4xl">
                {condition?.toLowerCase().includes('sun') ? '☀️' : 
                 condition?.toLowerCase().includes('cloud') ? '☁️' : 
                 condition?.toLowerCase().includes('rain') ? '🌧️' : '☀️'}
              </Text>
            </Stack>

            {/* Environmental Stats Box */}
            <Box
              padding={16}
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            >
              <Stack direction="horizontal" justify="around" align="center" gap={16}>
                <Stack direction="horizontal" gap={8} align="center">
                  <Text size="lg">💧</Text>
                  <Stack gap={0}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                    <Text variant="label">{humidity ?? 0}%</Text>
                  </Stack>
                </Stack>
                <Divider orientation="vertical" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />
                <Stack direction="horizontal" gap={8} align="center">
                  <Text size="lg">💨</Text>
                  <Stack gap={0}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
                    <Text variant="label">{windSpeed ?? 0} km/h</Text>
                  </Stack>
                </Stack>
              </Stack>
            </Box>

            <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            {/* 5-Day Forecast Strip */}
            <Stack gap={8}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-Day Forecast</Text>
              <Stack direction="horizontal" gap={8} justify="between" wrap={true}>
                {forecast?.map((item, index) => (
                  <div
                    key={`${item.day}-${index}`}
                    onMouseEnter={() => setHoverIndex(index)}
                    onMouseLeave={() => setHoverIndex(null)}
                    style={{ flex: '1 1 60px', minWidth: '60px' }}
                  >
                    <Box
                      padding={8}
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      background={hoverIndex === index ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                      style={{ 
                        transition: 'background-color 200ms ease',
                        border: hoverIndex === index ? '1px solid var(--ggui-color-primary-200, #bae6fd)' : '1px solid transparent'
                      }}
                    >
                      <Stack direction="vertical" align="center" gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                          {item.day ?? "Day"}
                        </Text>
                        <Text size="xl">{item.icon ?? "☀️"}</Text>
                        <Stack gap={2} align="center">
                          <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                            {item.high ?? 0}°
                          </Text>
                          <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                            {item.low ?? 0}°
                          </Text>
                        </Stack>
                      </Stack>
                    </Box>
                  </div>
                ))}
              </Stack>
            </Stack>
          </Stack>
        </Card>
      </div>
    </Container>
  );
}
